import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
import { truncateToWidth, visibleWidth } from "@mariozechner/pi-tui";

// Pastel yellow: #FFE066 → RGB(255, 224, 102)
const PASTEL_YELLOW_FG = "\x1b[38;2;255;224;102m";
const RESET = "\x1b[0m";

function yellow(text: string): string {
	return `${PASTEL_YELLOW_FG}${text}${RESET}`;
}

export default function (pi: ExtensionAPI) {
	pi.on("session_start", async (_event, ctx) => {
		ctx.ui.setFooter((_tui, _theme, _footerData) => ({
			invalidate() {},
			render(width: number): string[] {
				// --- Left side: pwd ---
				let pwd = ctx.sessionManager.getCwd() ?? "";
				const home = process.env.HOME || process.env.USERPROFILE;
				if (home && pwd.startsWith(home)) {
					pwd = `~${pwd.slice(home.length)}`;
				}

				// --- Right side: context meter ---
				const contextUsage = ctx.getContextUsage();
				const percent = contextUsage?.percent ?? 0;
				const displayPercent =
					contextUsage?.percent !== null && contextUsage?.percent !== undefined
						? `${Math.round(percent)}%`
						: "?%";

				// 10-step meter: filled blocks ■, empty = spaces
				const filledSteps = Math.min(10, Math.round(percent / 10));
				const emptySteps = 10 - filledSteps;
				const modelName = ctx.model?.id || "no-model";
				const thinkingLevel = pi.getThinkingLevel();
				const meter = `[${"■".repeat(filledSteps)}${" ".repeat(emptySteps)}] ${displayPercent}`;

				// --- Layout: left = pwd, right = model + meter ---
				const left = yellow(pwd);
				const right = yellow(`${thinkingLevel} • ${modelName} ${meter}`);

				const leftW = visibleWidth(left);
				const rightW = visibleWidth(right);
				const padding = " ".repeat(Math.max(1, width - leftW - rightW));

				return [truncateToWidth(left + padding + right, width), ""];
			},
		}));
	});
}

import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";

const messages = [
	// Dev workflow vibes
	"Building… don't forget to blame the cache",
	"Running tests… fingers crossed 🤞",
	"Compiling… this might take a coffee break",
	"Deploying… what could possibly go wrong?",
	"Installing dependencies… again",
	"Bundling assets like it's 2015",

	// Tooling jokes
	"Running npm install… see you soon",
	"Waiting for Docker to behave…",
	"Rebuilding containers… 🐳",
	"Asking Stack Overflow for help…",
	"Git pulling… hope nothing breaks",
	"Resolving merge conflicts… good luck",

	// Debugging humor
	"Debugging… it worked yesterday",
	"Chasing a missing semicolon…",
	"Fixing bugs… creating features",
	"Logging things we don't understand",
	"Stepping through code like a detective 🕵️",

	// Infra / backend flavor
	"Scaling horizontally… probably",
	"Waking up the servers…",
	"Querying the database… gently",
	"Negotiating with the API…",
	"Sending packets into the void…",

	// Playful + witty
	"Turning caffeine into code…",
	"Writing code that writes code…",
	'Making it "just work™"…',
	"Engineering in progress…",
	"Almost there… unless it crashes",

	// Sarcastic loading humor
	"Discovering new ways of making you wait.",
	"Your time is very important to us. Please wait while we ignore you.",
	"Still faster than Windows update.",
	"We are not liable for any broken screens as a result of waiting.",
	"Bored of slow loading spinner? Buy more RAM!",
	"Kindly hold on until I finish a cup of coffee.",
	"We will be back in 1/0 minutes.",
	"Why don't you order a sandwich?",
	"Don't panic, just count to infinite.",
	"Please wait, your PC is not a superman!",
];

let lastIdx = -1;

function randomMessage(): string {
	let idx: number;
	do {
		idx = Math.floor(Math.random() * messages.length);
	} while (idx === lastIdx && messages.length > 1);
	lastIdx = idx;
	return messages[idx];
}

export default function (pi: ExtensionAPI) {
	pi.on("agent_start", async (_event, ctx) => {
		if (ctx.hasUI) {
			ctx.ui.setWorkingMessage(randomMessage());
		}
	});

	pi.on("turn_start", async (_event, ctx) => {
		if (ctx.hasUI) {
			ctx.ui.setWorkingMessage(randomMessage());
		}
	});
};

/**
 * Permission Gate Extension
 *
 * Blocks dangerous bash commands before they execute.
 * This replicates the safety behavior that Claude Code provides by default.
 *
 * Drop this in ~/.pi/agent/extensions/ and it auto-loads.
 */
import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";

const DANGEROUS_PATTERNS = [
  /rm\s+(-rf|-fr)\s+[\/~]/,  // rm -rf with absolute/home paths
  />\s*\/dev\/sd/,            // writing to block devices
  /mkfs\./,                   // formatting filesystems
  /dd\s+if=/,                 // raw disk writes
  /chmod\s+777/,              // overly permissive permissions
  /curl.*\|\s*(ba)?sh/,       // pipe curl to shell
];

export default function (pi: ExtensionAPI) {
  pi.on("tool_call", async (event, ctx) => {
    if (event.tool !== "bash") return;

    const command = event.input.command as string;

    for (const pattern of DANGEROUS_PATTERNS) {
      if (pattern.test(command)) {
        if (ctx.hasUI) {
          const allow = await ctx.ui.confirm(
            `Blocked dangerous command:\n${command}\n\nAllow anyway?`
          );
          if (allow) return;
        }
        return { block: true, reason: `Blocked dangerous command: ${command}` };
      }
    }
  });
}

/**
 * Side-by-Side Diff Extension
 *
 * Replaces the default inline diff rendering for the edit tool with a
 * two-column "Previous" (left) / "Now" (right) card layout with colored
 * backgrounds highlighting deletions (red) and additions (green).
 *
 * Works during both the live preview phase (renderCall, while args stream)
 * and after execution (renderResult).
 *
 * Usage: drop in ~/.pi/agent/extensions/ and /reload
 */

import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
import { createEditToolDefinition } from "@mariozechner/pi-coding-agent";
import { Container, Spacer, Text } from "@mariozechner/pi-tui";
import { Type } from "@sinclair/typebox";
import { visibleWidth, truncateToWidth, wrapTextWithAnsi } from "@mariozechner/pi-tui";

// ---------------------------------------------------------------------------
// ANSI helpers
// ---------------------------------------------------------------------------

function bgRgb(r: number, g: number, b: number, text: string): string {
	return `\x1b[48;2;${r};${g};${b}m${text}\x1b[49m`;
}

function fgRgb(r: number, g: number, b: number, text: string): string {
	return `\x1b[38;2;${r};${g};${b}m${text}\x1b[39m`;
}

// ---------------------------------------------------------------------------
// Side-by-side diff component
// ---------------------------------------------------------------------------

interface DiffLine {
	type: "removed" | "added" | "context" | "ellipsis";
	lineNum: string;
	content: string;
}

class SideBySideDiff extends Container {
	private parsedLines: DiffLine[];
	private cachedWidth?: number;
	private cachedLines?: string[];

	constructor(
		private diffText: string,
		private theme: any,
		private filePath?: string,
	) {
		super();
		this.parsedLines = this.parseDiff(diffText);
	}

	private parseDiff(diffText: string): DiffLine[] {
		const lines: DiffLine[] = [];
		for (const raw of diffText.split("\n")) {
			const match = raw.match(/^([+\-\s])\s*(\d*)\s(.*)$/);
			if (!match) {
				if (/^\s+\.\.\./.test(raw)) {
					lines.push({ type: "ellipsis", lineNum: "", content: "..." });
				}
				continue;
			}
			const [, prefix, lineNum, content] = match;
			if (prefix === "-") {
				lines.push({ type: "removed", lineNum, content });
			} else if (prefix === "+") {
				lines.push({ type: "added", lineNum, content });
			} else {
				lines.push({ type: "context", lineNum, content });
			}
		}
		return lines;
	}

	override render(width: number): string[] {
		if (this.cachedLines && this.cachedWidth === width) {
			return this.cachedLines;
		}

		const gap = 1;
		const leftWidth = Math.floor((width - gap) / 2);
		const rightWidth = width - leftWidth - gap;

		if (leftWidth < 12 || rightWidth < 12) {
			return super.render(width);
		}

		const lines: string[] = [];
		const sep = this.theme.fg("border", "│");

		// ── Padding ──
		const padX = 1;
		const padY = 1;
		const innerLeft = leftWidth - padX;
		const innerRight = rightWidth - padX;

		// ── Card backgrounds ──
		const cardBg = (t: string) => bgRgb(30, 30, 42, t);
		const delBg = (t: string) => bgRgb(55, 24, 24, t);
		const addBg = (t: string) => bgRgb(22, 45, 22, t);

		const px = " ".repeat(padX);

		const row = (leftContent: string, leftBgFn: (t: string) => string, rightContent: string, rightBgFn: (t: string) => string) => {
			return leftBgFn(px + pad(leftContent, innerLeft)) + sep + rightBgFn(px + pad(rightContent, innerRight));
		};

		const emptyRow = () => row("", cardBg, "", cardBg);

		// ── Top padding ──
		for (let i = 0; i < padY; i++) lines.push(emptyRow());

		// ── Title row (edit file.ext) spanning full width ──
		if (this.filePath) {
			const title = this.theme.fg("toolTitle", this.theme.bold(`edit ${this.filePath}`));
			lines.push(
				cardBg(px + pad(title, leftWidth - padX))
				+ sep
				+ cardBg(" ".repeat(rightWidth)),
			);
		}

		// ── Spacer between title and columns ──
		if (this.filePath) {
			lines.push(emptyRow());
		}

		// ── Column headers ──
		const leftTitle = this.theme.bold(fgRgb(255, 130, 130, "Previous"));
		const rightTitle = this.theme.bold(fgRgb(130, 230, 130, "Now"));
		lines.push(row(leftTitle, cardBg, rightTitle, cardBg));

		// ── Body rows (with word-wrap) ──
		for (const dl of this.parsedLines) {
			let left = "";
			let right = "";
			let leftBg = cardBg;
			let rightBg = cardBg;

			switch (dl.type) {
				case "removed":
					left = this.theme.fg("toolDiffRemoved", `${dl.lineNum} ${dl.content}`);
					leftBg = delBg;
					break;
				case "added":
					right = this.theme.fg("toolDiffAdded", `${dl.lineNum} ${dl.content}`);
					rightBg = addBg;
					break;
				case "context":
					left = this.theme.fg("toolDiffContext", `${dl.lineNum} ${dl.content}`);
					right = left;
					break;
				case "ellipsis":
					left = this.theme.fg("dim", "...");
					right = left;
					break;
			}

			const leftWrapped = wrapCell(left, innerLeft);
			const rightWrapped = wrapCell(right, innerRight);

			const maxRows = Math.max(leftWrapped.length, rightWrapped.length);
			while (leftWrapped.length < maxRows) leftWrapped.push("");
			while (rightWrapped.length < maxRows) rightWrapped.push("");

			for (let i = 0; i < maxRows; i++) {
				lines.push(
					leftBg(px + pad(leftWrapped[i], innerLeft))
					+ sep
					+ rightBg(px + pad(rightWrapped[i], innerRight)),
				);
			}
		}

		// ── Bottom padding ──
		for (let i = 0; i < padY; i++) lines.push(emptyRow());

		this.cachedWidth = width;
		this.cachedLines = lines;
		return lines;
	}

	override invalidate(): void {
		this.cachedWidth = undefined;
		this.cachedLines = undefined;
		super.invalidate();
	}
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function pad(text: string, width: number): string {
	const vis = visibleWidth(text);
	if (vis >= width) return truncateToWidth(text, width, "");
	return text + " ".repeat(width - vis);
}

function wrapCell(text: string, width: number): string[] {
	if (!text || width <= 0) return [""];
	if (visibleWidth(text) <= width) return [text];
	return wrapTextWithAnsi(text, width);
}

/** Extract a short display path from tool args */
function formatPath(args: any): string | undefined {
	const rawPath = args?.file_path ?? args?.path;
	if (typeof rawPath !== "string" || !rawPath) return undefined;
	return rawPath.length > 50 ? "..." + rawPath.slice(-47) : rawPath;
}

// ---------------------------------------------------------------------------
// Extension
// ---------------------------------------------------------------------------

const editSchema = Type.Object({
	path: Type.String({ description: "Path to the file to edit" }),
	edits: Type.Array(
		Type.Object({
			oldText: Type.String(),
			newText: Type.String(),
		}),
	),
});

export default function (pi: ExtensionAPI) {
	const builtIn = createEditToolDefinition(process.cwd());

	pi.registerTool({
		name: "edit",
		label: "edit",
		description: builtIn.description,
		promptSnippet: builtIn.promptSnippet,
		promptGuidelines: builtIn.promptGuidelines,
		parameters: editSchema,
		prepareArguments: builtIn.prepareArguments,
		renderShell: "self" as const,

		async execute(toolCallId, params, signal, onUpdate, ctx) {
			return builtIn.execute(toolCallId, params, signal, onUpdate, ctx);
		},

		renderCall(args: any, theme: any, context: any) {
			// Let built-in manage async preview lifecycle (stores in context.state.callComponent)
			builtIn.renderCall!(args, theme, context);

			// Check if preview diff is available
			const preview = context.state?.callComponent?.preview;
			const diff = preview && !("error" in preview) ? preview.diff : undefined;

			// Build our own component
			const container = new Container();

			if (diff) {
				container.addChild(new SideBySideDiff(diff, theme, formatPath(args)));
			} else {
				// No diff yet — show simple header while preview loads
				container.addChild(new Text(theme.fg("toolTitle", theme.bold("edit")) + " " + theme.fg("accent", formatPath(args) ?? "..."), 0, 0));
				if (preview && "error" in preview) {
					container.addChild(new Spacer(1));
					container.addChild(new Text(theme.fg("error", preview.error), 1, 0));
				}
			}

			return container;
		},

		renderResult(_result: any, _options: any, theme: any, context: any) {
			if (context.isError) {
				const errorText = _result.content
					?.filter((c: any) => c.type === "text")
					?.map((c: any) => c.text || "")
					?.join("\n") || "Error";
				const container = new Container();
				container.addChild(new Text(theme.fg("toolTitle", theme.bold("edit")), 0, 0));
				container.addChild(new Spacer(1));
				container.addChild(new Text(theme.fg("error", errorText), 1, 0));
				return container;
			}

			// The diff is already shown by renderCall during the preview phase.
			// ToolExecutionComponent stacks both renderCall + renderResult,
			// so return empty to avoid duplicating the card.
			return new Container();
		},
	});
}

